package edu.rice.comp322;

import edu.rice.hj.api.SuspendableException;

/**
 * A scorer that allocates memory during computation, so that it may compute the scores for two sequences without
 * requiring O(|X||Y|) memory.
 */
public class SparseParScoring extends AbstractDnaScoring {

    private final int xLength;
    private final int yLength;
    private final int[][] horizontalBoundary;
    private final int[][] verticalBoundary;
    private static final int B = 512; // Block size

    /**
     * <p>main.</p> Takes the names of two files, and in parallel calculates the sequence aligment scores of the two DNA
     * strands that they represent.
     *
     * @param args The names of two files.
     */
    public static void main(final String[] args) throws Exception {
        final ScoringRunner scoringRunner = new ScoringRunner(SparseParScoring::new);
        scoringRunner.start("SparseParScoring", args);
    }

    /**
     * Creates a new SparseParScoring.
     *
     * @param xLength length of the first sequence
     * @param yLength length of the second sequence
     */
    public SparseParScoring(final int xLength, final int yLength) {
        if (xLength <= 0 || yLength <= 0) {
            throw new IllegalArgumentException("Lengths (" + xLength + ", " + yLength + ") must be positive!");
        }

        this.xLength = xLength;
        this.yLength = yLength;

        final int nx = (xLength + B - 1) / B;
        final int ny = (yLength + B - 1) / B;

        // Allocate only the boundaries between blocks
        this.horizontalBoundary = new int[nx + 1][yLength + 1];
        this.verticalBoundary = new int[xLength + 1][ny + 1];

        final int gapX = getScore(1, 0);
        final int gapY = getScore(0, 1);

        // Initialize boundary conditions
        for (int j = 0; j <= yLength; j++) {
            horizontalBoundary[0][j] = j * gapY;
        }
        for (int i = 0; i <= xLength; i++) {
            verticalBoundary[i][0] = i * gapX;
        }
    }

    /**
     * Here you should implement a parallel version of the SW alignment algorithm that can support datasets where the
     * size of the S matrix exceeds the available memory.
     * {@inheritDoc}
     */
    public int scoreSequences(final String x, final String y) throws SuspendableException {
        final int nx = (xLength + B - 1) / B;
        final int ny = (yLength + B - 1) / B;

        for (int k = 2; k <= nx + ny; k++) {
            final int diagonal = k;
            edu.rice.hj.Module1.finish(() -> {
                for (int bi = Math.max(1, diagonal - ny); bi <= Math.min(nx, diagonal - 1); bi++) {
                    final int blockI = bi;
                    final int blockJ = diagonal - blockI;

                    edu.rice.hj.Module1.async(() -> {
                        final int istart = (blockI - 1) * B + 1;
                        final int iend = Math.min(blockI * B, xLength);
                        final int jstart = (blockJ - 1) * B + 1;
                        final int jend = Math.min(blockJ * B, yLength);

                        final int height = iend - istart + 1;
                        final int width = jend - jstart + 1;

                        // Local block to store current computations
                        final int[][] blockS = new int[height + 1][width + 1];

                        // Fill block boundaries from boundary arrays
                        for (int j = 1; j <= width; j++) {
                            blockS[0][j] = horizontalBoundary[blockI - 1][jstart + j - 1];
                        }
                        for (int i = 1; i <= height; i++) {
                            blockS[i][0] = verticalBoundary[istart + i - 1][blockJ - 1];
                        }
                        blockS[0][0] = horizontalBoundary[blockI - 1][jstart - 1];

                        // Sequential computation within the block
                        for (int i = 1; i <= height; i++) {
                            final char xChar = x.charAt(istart + i - 2);
                            final int xIdx = charMap(xChar);
                            final int scoreX0 = getScore(xIdx, 0);
                            for (int j = 1; j <= width; j++) {
                                final char yChar = y.charAt(jstart + j - 2);

                                final int diagScore = blockS[i - 1][j - 1] + getScore(xIdx, charMap(yChar));
                                final int topColScore = blockS[i - 1][j] + scoreX0;
                                final int leftRowScore = blockS[i][j - 1] + getScore(0, charMap(yChar));
                                blockS[i][j] = Math.max(diagScore, Math.max(leftRowScore, topColScore));
                            }
                        }

                        // Store results back to boundary arrays
                        for (int j = 1; j <= width; j++) {
                            horizontalBoundary[blockI][jstart + j - 1] = blockS[height][j];
                        }
                        for (int i = 1; i <= height; i++) {
                            verticalBoundary[istart + i - 1][blockJ] = blockS[i][width];
                        }
                    });
                }
            });
        }
        return horizontalBoundary[nx][yLength];
    }
}
